4	describe("Game of Life", () => {
5	  it("should return an empty grid when given an empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill a live cell with only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive with exactly two neighbors (survival)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
16	    const sorted = result.map(([x, y]) => [x, y]).sort((a, b) => a[0] - b[0] || a[1] - b[1]);
17	    expect(sorted).toEqual([[1, -1], [1, 0], [1, 1]]);
18	  });
19	  it.todo("should keep a live cell alive with exactly three neighbors (survival)");
20	  it.todo("should kill a live cell with four neighbors (overpopulation)");
21	  it.todo("should create a live cell from a dead cell with exactly three live neighbors (reproduction)");
22	  it.todo("should not create a live cell from a dead cell with only two live neighbors");
23	  it.todo("should handle a block still life (2x2 square remains unchanged)");
24	  it.todo("should handle a blinker oscillator (three in a row toggles orientation)");
25	  it.todo("should support negative coordinates");
26	});
